const fetchData = () => {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const success = true; // Simulate success or failure
      if (success) {
        resolve('Data received!');
      } else {
        reject('Error occurred');
      }
    }, 1000);
  });
};

fetchData()
  .then(data => console.log(data))
  .catch(error => console.error(error));

const fetchDataAsync = () => {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve('Data received!');
    }, 1000);
  });
};

async function getData() {
  try {
    const data = await fetchDataAsync();
    console.log(data);
  } catch (error) {
    console.error(error);
  }
}

getData();

async function sequentialTasks() {
  const first = await fetchDataAsync();
  console.log('First:', first);

  const second = await fetchDataAsync();
  console.log('Second:', second);
}

sequentialTasks();

Promise.all([fetchDataAsync(), fetchDataAsync()])
  .then(results => {
    console.log('Results:', results);
  })
  .catch(error => {
    console.error(error);
  });

async function parallelTasks() {
  try {
    const results = await Promise.all([fetchDataAsync(), fetchDataAsync()]);
    console.log('Results:', results);
  } catch (error) {
    console.error(error);
  }
}

parallelTasks();

class ValidationError extends Error {
  constructor(message) {
    super(message); // Call the parent class constructor
    this.name = 'ValidationError'; // Set error name to your class name
  }
}

// Example usage
function validateUsername(username) {
  if (username.length < 5) {
    throw new ValidationError('Username must be at least 5 characters long.');
  }
  return true;
}

try {
  validateUsername('abc');
} catch (error) {
  if (error instanceof ValidationError) {
    console.error('Validation failed:', error.message);
  } else {
    console.error('Unexpected error:', error);
  }
}

class ValidationError extends Error {
  constructor(message, code) {
    super(message);
    this.name = 'ValidationError';
    this.code = code; // Custom error code
  }
}

try {
  throw new ValidationError('Invalid email format.', 'E_INVALID_EMAIL');
} catch (error) {
  console.error(`${error.name} (${error.code}): ${error.message}`);
}

